"use strict";

const fs = require("fs");
const path = require("path");

const root = path.resolve(__dirname, "..");
const sources = [
  "max/javascript/live_value_helpers.js",
  "max/javascript/naming_engine.js",
  "max/javascript/live_controller.js",
];
function createOutputs(projectRoot = root) {
  const banner = "/* GENERATED by scripts/build_max_js_bundle.js. Edit max/javascript sources, then rebuild. */\n";
  const content = banner + sources.map((source) => `\n/* BEGIN ${source} */\n${fs.readFileSync(path.join(projectRoot, source), "utf8")}\n/* END ${source} */\n`).join("");
  const outputs = new Map();
  for (const target of ["drumslice_id_bundle.js", "drumslice_id_bundle_v2.js"]) {
    outputs.set(path.join(projectRoot, "max/patchers", target), content);
  }
  for (const [source, targets] of [
    ["max/javascript/results_controller.js", ["max/patchers/drumslice_id_results_bundle.js", "max/patchers/drumslice_id_results_bundle_v2.js"]],
    ["max/javascript/settings_controller.js", ["max/patchers/drumslice_id_settings_bundle.js", "max/patchers/drumslice_id_settings_bundle_v2.js"]],
  ]) {
    const generated = `/* GENERATED by scripts/build_max_js_bundle.js from ${source}. */\n${fs.readFileSync(path.join(projectRoot, source), "utf8")}`;
    for (const target of targets) outputs.set(path.join(projectRoot, target), generated);
  }
  return outputs;
}

function checkOutputs(outputs, projectRoot = root) {
  const stale = [];
  for (const [target, expected] of outputs) {
    let actual = "";
    try { actual = fs.readFileSync(target, "utf8"); } catch {}
    if (actual !== expected) stale.push(path.relative(projectRoot, target));
  }
  return stale;
}

function writeAtomic(target, content) {
  fs.mkdirSync(path.dirname(target), {recursive: true});
  const temporary = `${target}.tmp-${process.pid}`;
  try {
    fs.writeFileSync(temporary, content, "utf8");
    fs.renameSync(temporary, target);
  } finally {
    try { fs.unlinkSync(temporary); } catch (error) { if (error.code !== "ENOENT") throw error; }
  }
}

function writeOutputs(outputs) {
  for (const [target, expected] of outputs) writeAtomic(target, expected);
}

function main(argv) {
  if (argv.length > 1 || (argv.length === 1 && argv[0] !== "--check")) {
    throw new Error("Usage: build_max_js_bundle.js [--check]");
  }
  const outputs = createOutputs();
  if (argv[0] === "--check") {
    const stale = checkOutputs(outputs);
    if (stale.length) throw new Error(`Generated Max JavaScript is stale: ${stale.join(", ")}\nRun node scripts/build_max_js_bundle.js.`);
  } else writeOutputs(outputs);
}

if (require.main === module) {
  try { main(process.argv.slice(2)); }
  catch (error) {
    process.stderr.write(`${error.message}\n`);
    process.exitCode = 1;
  }
}

module.exports = {checkOutputs, createOutputs, main, writeOutputs};
